145		-- *** CheckLastActivityStlv ***
146		procedure CheckLastActivityStlv(signal Sig : in std_logic_vector;
147		                                IdleTime   : in time;
148		                                Level      : in integer range -1 to integer'high; -- -1 = don't check, otherwise interpreted unsigned
149		                                Msg        : in string := "";
150		                                Prefix     : in string := "###ERROR###: ") is
